(function($){"use strict";const{subscribe,select}=wp.data;const CHECKOUT_STORE_KEY="wc/store/checkout";let lastEmail="";let debounceTimer=null;function sendCartData(billingData){const email=billingData.email||"";if(!email||email===lastEmail||!email.includes("@")){return}
lastEmail=email;clearTimeout(debounceTimer);debounceTimer=setTimeout(()=>{const payload={email:email,first_name:billingData.first_name||"",last_name:billingData.last_name||"",phone:billingData.phone||"",cart_key:ghlAbandonedCart.cartKey||"",user_id:ghlAbandonedCart.userId||0,};fetch(ghlAbandonedCart.restUrl,{method:"POST",headers:{"Content-Type":"application/json",},body:JSON.stringify(payload),}).then((response)=>{if(response.ok){return response.json()}else{response.json().then((data)=>{console.error("GHL: Error response:",data)})}}).catch((error)=>{console.error("GHL: Error tracking cart",error)})},1000)}
function monitorCheckoutData(){if(!select(CHECKOUT_STORE_KEY)){setTimeout(monitorCheckoutData,500);return}
let previousBillingAddress={};let initialCaptureDone=!1;function captureFromDOM(){const emailInput=document.getElementById("email");const firstNameInput=document.getElementById("billing-first_name")||document.querySelector('input[name="billing-first_name"]');const lastNameInput=document.getElementById("billing-last_name")||document.querySelector('input[name="billing-last_name"]');const phoneInput=document.getElementById("billing-phone")||document.querySelector('input[name="billing-phone"]');if(emailInput&&emailInput.value&&emailInput.value.includes("@")){const billingData={email:emailInput.value,first_name:firstNameInput?firstNameInput.value:"",last_name:lastNameInput?lastNameInput.value:"",phone:phoneInput?phoneInput.value:"",};previousBillingAddress={...billingData};sendCartData(billingData);initialCaptureDone=!0;return!0}
return!1}
setTimeout(()=>{if(!initialCaptureDone){captureFromDOM()}},1000);function setupInputListeners(){const emailInput=document.getElementById("email");const firstNameInput=document.getElementById("billing-first_name")||document.querySelector('input[name="billing-first_name"]');const lastNameInput=document.getElementById("billing-last_name")||document.querySelector('input[name="billing-last_name"]');const phoneInput=document.getElementById("billing-phone")||document.querySelector('input[name="billing-phone"]');if(emailInput){emailInput.addEventListener("input",function(){if(emailInput.value&&emailInput.value.includes("@")){const billingData={email:emailInput.value,first_name:firstNameInput?firstNameInput.value:"",last_name:lastNameInput?lastNameInput.value:"",phone:phoneInput?phoneInput.value:"",};sendCartData(billingData)}});emailInput.addEventListener("blur",function(){if(emailInput.value&&emailInput.value.includes("@")){const billingData={email:emailInput.value,first_name:firstNameInput?firstNameInput.value:"",last_name:lastNameInput?lastNameInput.value:"",phone:phoneInput?phoneInput.value:"",};sendCartData(billingData)}})}else{setTimeout(setupInputListeners,500)}}
setTimeout(setupInputListeners,500);subscribe(()=>{try{const billingAddress=select(CHECKOUT_STORE_KEY).getBillingAddress?.()||{};if(!initialCaptureDone&&billingAddress.email){previousBillingAddress={...billingAddress};sendCartData(billingAddress);initialCaptureDone=!0;return}
if(billingAddress.email){const addressChanged=billingAddress.email!==previousBillingAddress.email||billingAddress.first_name!==previousBillingAddress.first_name||billingAddress.last_name!==previousBillingAddress.last_name||billingAddress.phone!==previousBillingAddress.phone;if(addressChanged){previousBillingAddress={...billingAddress};sendCartData(billingAddress)}}}catch(error){}})}
$(document).ready(function(){if($(".wp-block-woocommerce-checkout").length>0){monitorCheckoutData()}})})(jQuery)